## Learnable Early Exiting for Diffusion Transformers

Diffusion models are slow; many layers redundant. Learnable exiting lets model skip layers when confident.

## Implementation

```python
class EarlyExitDiffusion(nn.Module):
    def __init__(self, base_diffusion):
        super().__init__()
        self.diffusion = base_diffusion
        # Exit decision at each layer
        self.exit_gates = nn.ModuleList([
            nn.Sequential(nn.Linear(hidden_dim, 1), nn.Sigmoid())
            for _ in range(num_layers)
        ])

    def forward(self, x, t, threshold=0.7):
        for i, layer in enumerate(self.diffusion.layers):
            x = layer(x)
            # Should we exit early?
            exit_prob = self.exit_gates[i](x)
            if exit_prob > threshold:
                return x  # Skip remaining layers
        return x

def train_with_early_exit(model, data, lambda_exit=0.1):
    """Trade-off: accuracy vs speed"""
    for batch in data:
        output = model(batch)
        recon_loss = mse(output, batch)
        exit_loss = sum(gate(x).mean() for gate in model.exit_gates)
        total_loss = recon_loss + lambda_exit * exit_loss
        total_loss.backward()
```
